// Arma el body del pedido a OpenAI y preserva info del mensaje.
// Tolera mensajes sin texto (sticker/foto/voz) — responde con help.
const msg = $json.message || {};
const userText = (msg.text || '').trim();
const chat_id = msg.chat && msg.chat.id;

const systemPrompt = [
  'Sos un asistente para el admin de Party House.',
  'Extraé del mensaje los datos del invitado que el admin quiere crear.',
  'Responde SIEMPRE con JSON puro, sin markdown. Usá uno de estos 3 formatos:',
  '1) Si hay datos suficientes (al menos first_name):',
  '   {"action":"create_code","first_name":"...","last_name":"...","email":"...","phone":"..."}',
  '2) Si falta información:',
  '   {"action":"ask","message":"Pedile al usuario lo que falta"}',
  '3) Si el mensaje no es una orden válida:',
  '   {"action":"help","message":"Ejemplo: crea código para Juan Pérez, juan@example.com, +5255123456"}'
].join('\n');

const body = {
  model: 'gpt-4o-mini',
  temperature: 0,
  response_format: { type: 'json_object' },
  messages: [
    { role: 'system', content: systemPrompt },
    { role: 'user', content: userText || 'hola' }
  ]
};

return [{ json: { chat_id, userText, openai_body: body } }];

// Parsea la respuesta de OpenAI (formato estándar chat completions)
// y construye el código si hay datos suficientes.
const EVENT_ID = 'bdf59dc5-a260-4be9-99b4-81450982c8d6';

const prepItems = $items('Preparar pedido OpenAI');
const prep = (prepItems && prepItems[0] && prepItems[0].json) || {};
const chat_id = prep.chat_id;

let aiContent = '';
try {
  aiContent = $json.choices && $json.choices[0] && $json.choices[0].message
    ? $json.choices[0].message.content
    : '';
} catch (e) {
  aiContent = '';
}

let ai = {};
try { ai = JSON.parse(aiContent || '{}'); }
catch (e) {
  ai = { action: 'help', message: 'No pude entender. Probá: "crea código para Juan Pérez, juan@example.com"' };
}

if (ai.action !== 'create_code' || !ai.first_name) {
  const helpMsg = ai.message || 'No entendí. Probá: "crea código para Juan Pérez, juan@example.com"';
  return [{ json: { needs_reply: true, chat_id, text: helpMsg } }];
}

const clean = (s) => String(s || '').normalize('NFD').replace(/[\u0300-\u036f]/g, '').replace(/[^A-Za-z0-9]/g, '').toUpperCase();
const firstPart = clean(ai.first_name).slice(0, 6) || 'GUEST';
const lastPart  = clean(ai.last_name).slice(0, 3);
const digits    = String(Math.floor(Math.random() * 9000) + 1000);
const code      = lastPart ? `${firstPart}-${lastPart}-${digits}` : `${firstPart}-${digits}`;

return [{ json: {
  needs_reply: false,
  chat_id,
  first_name: ai.first_name,
  last_name:  ai.last_name || '',
  email:      ai.email || null,
  phone:      ai.phone || null,
  event_id:   EVENT_ID,
  code
}}];

